sql:
SELECT v.make, v.model, ft.fueltype_name
FROM vehicles v
INNER JOIN fuel_types ft ON v.fueltype_id = ft.fueltype_id;

external_knowledge:
- "Breathed life after 2010" refers to vehicles manufactured after the year 2010;
- "Emit more than 150 units of CO2 on average" refers to the average CO2 emissions being greater than 150;
- "Type" and "drivetrain" refer to the `category_id` and `drivetype_id` of the vehicles, respectively.

sql:
SELECT AVG(city) AS average_city_fuel_economy
FROM fuel_economies
WHERE vehicle_id = 1;
